#include <array>
#include <iostream>

bool is_even(long long value) { return value % 2 == 0; }

int main() {
    const std::array<std::pair<long long, bool>, 4> checks{{{0, true}, {-2, true}, {1, false}, {7, false}}};
    for (const auto& [input, expected] : checks) if (is_even(input) != expected) return 2;
    long long value{};
    if (!(std::cin >> value)) return 1;
    std::cout << (is_even(value) ? "even" : "odd") << '\n';
}
